mapper.select:
SELECT CF_SEQ, FAMILY_ID, CC_SEQ, CC_NM, FLOW_TYPE, FLOW_YYMM, TITLE, ACTUAL_AMT, MEMO
FROM MANUAL_CASHFLOW_HST
WHERE FAMILY_ID = #{familyId}
  AND HST_YYMM  = #{yymm}
ORDER BY FLOW_TYPE DESC, CC_SEQ, CF_SEQ

SELECT CC_SEQ, CC_NM, CC_TYPE, INCOME_PLAN_NM, INCOME_AMT, EXPENSE_AMT, BALANCE
FROM COST_CENTER_HST
WHERE FAMILY_ID = #{familyId}
  AND HST_YYMM  = #{yymm}
ORDER BY CC_SEQ
